import React, {createContext, type FC, type PropsWithChildren, useCallback, useEffect, useRef, useState} from "react";
import AsyncStorage from "@react-native-async-storage/async-storage";
import {initMobileI18n} from "@lmb-it/kitsconcertomobile/i18n"; // ← our new initializer
import localeFiles from "../../Locale"; // built-in languages
import type {ILocaleContextProps, ILocaleContextValues,} from "@lmb-it/kitsconcerto-types";
import i18n from "i18next";

export const LocaleContext = createContext<ILocaleContextValues>(
    {} as ILocaleContextValues
);

const STORAGE_KEY = "currentLanguage";

const LocaleContextProvider: FC<PropsWithChildren<ILocaleContextProps>> = ({
                                                                               children,
                                                                               languages,
                                                                               defaultLanguage = "en",
                                                                               onChangeLanguage
                                                                           }) => {

    const defaultLocal = useRef<string>("");
    const [language, setLanguage] = useState(defaultLanguage);
    const [isRTL, setIsRTL] = useState(defaultLanguage === "ar");

    // Build extra translations from props to match the expected format


    const translationsList = () => {
        const l: any = {};

        Object.keys(localeFiles).forEach(key => {
            l[key] = {translation: localeFiles[key]};
        })

        if (languages) {
            languages.forEach(({lang, translations}) => {
                if (lang in l) {
                    l[lang] = {
                        translation: {
                            ...l[lang].translation,
                            ...translations
                        }
                    };
                } else {
                    l[lang] = {
                        translation: {
                            ...translations
                        }
                    };
                }

            })
        }
        return l;
    }

    // Initialize i18next on mount
    useEffect(() => {
        if (defaultLocal.current == defaultLanguage) return;
        const init = async () => {

            await initMobileI18n(translationsList());     // ← initialize i18n (merges base + user)

            // restore saved language
            const stored = await AsyncStorage.getItem(STORAGE_KEY);
            const lang = stored || defaultLanguage;

            await i18n.changeLanguage(lang);
            setLanguage(lang);
            setIsRTL(lang === "ar");

            defaultLocal.current = defaultLanguage
        };

        void init();
    }, [defaultLanguage]);


    const isKeyExists = (key: string)=>{
        return i18n.exists(key)
    }
    // Change language (writes to AsyncStorage + updates context + updates i18next)
    const changeLanguage = useCallback(
        async (newLang: string) => {
            setLanguage(newLang);
            setIsRTL(newLang === "ar");

            await i18n.changeLanguage(newLang);

            await AsyncStorage.setItem(STORAGE_KEY, newLang);

            onChangeLanguage?.(newLang);
        },
        [onChangeLanguage]
    );

    // t() now comes directly from i18next
    const t = useCallback(
        (key: string, ...params: (string | number)[]) =>
            i18n.t(key, {replace: params}),
        []
    );

    return (
        <LocaleContext.Provider
            value={{
                t,
                changeLanguage,
                currentLanguage: language,
                isRTL,
                isKeyExists
            }}
        >
            {children}
        </LocaleContext.Provider>
    );
};

export default LocaleContextProvider;
